"""
mkt-context layer — 1 Corinthians chapters 9–11
Output: data/commentary/mkt-context/1corinthians.json
Run: python3 scripts/zc-context-1corinthians-9-11.py
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys — safe to re-run.
    # CHANGE? If commentary JSON structure changes from {ch:{v:html}}, update this traversal.
    # VERIFY: Re-running the script should produce identical output.
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW = {
  "9": {
    "1": "Apostolic freedom in a patronage society: Paul's insistence that he is free (eleutheros) resonates with Corinthian social values, where freedom was the prized status of the Roman citizen. In a city built on Roman patronage networks, Paul's refusal of patron support was countercultural — patrons expected deference and public honor from those they funded.",
    "2": "The seal of apostleship: in Roman legal culture, a seal (sphragis) was the validating mark on official documents. Paul applies the metaphor to the Corinthian community itself as the verification of his commission — living proof that his ministry was genuine.",
    "3": "Formal defense (apologia): the language of 9:3 is drawn from Hellenistic legal procedure. Apologia was the formal reply submitted by the accused party in a legal proceeding. Paul is responding to an actual examination of his apostolic credentials by some in Corinth.",
    "4": "The right to eat and drink at community expense: in the Greco-Roman world, philosophers and teachers were often supported by wealthy patrons or civic bodies. Sophists charged fees; Cynics begged; Epicureans lived in self-sufficient communities. Paul's self-support by tent-making set him apart from all these models.",
    "5": "Apostolic wives: Peter (Cephas) and the brothers of the Lord traveling with their wives was known to the Corinthians. Josephus confirms that Jewish missionaries traveled with families (Antiquities 20.2.4). The brothers of the Lord (James, Joses, Simon, Judas — Matt 13:55) were real figures known in early churches.",
    "6": "Barnabas as a working missionary: the reference confirms that Barnabas also worked to support himself — unusual among recognized apostolic figures. This places both Paul and Barnabas outside the standard pattern of apostolic support.",
    "7": "Military and agricultural analogies: Roman soldiers received stipendia (military pay) as a matter of legal right — the soldier who serves at his own expense violates the military contract. The vine-keeper and shepherd illustrations draw on agricultural realities familiar to any Mediterranean audience.",
    "8": "Law as foundation for ethical argument: Paul moves from common-sense analogies to scriptural grounding. In Jewish rhetorical practice, the hierarchy of proof ran from scripture downward; invoking the Torah placed the argument on the highest possible ground.",
    "9": "Deuteronomy 25:4 — do not muzzle an ox: the ox-muzzle law was a genuine Mosaic agricultural regulation. Philo (Special Laws 1.260) and the rabbis interpreted it literally as humanitarian concern for animals. Paul reads it as primarily intended for human workers — an allegorical/typological move consistent with his interpretive practice.",
    "10": "Farmer's hope in the harvest: Mediterranean farming was subsistence-level for most; the expectation of sharing in the crop was not a luxury but a survival principle. Paul's argument carries existential weight for an agrarian audience even in a commercial city like Corinth.",
    "11": "Spiritual vs. material reciprocity: the exchange Paul describes (spiritual seed for material harvest) mirrors the philosophical discussion of benefaction in Greco-Roman ethics. Seneca (On Benefits) analyzed the reciprocal obligations created by gifts; Paul employs the same framework while inverting its assumptions.",
    "12": "The enkopē (obstacle) metaphor: enkopē is a military engineering term for cutting a trench across a road to impede an enemy advance. Paul uses it for anything that blocks the forward progress of the gospel — a remarkably martial image for the apostle who insists he uses no worldly weapons (2 Cor 10:4).",
    "13": "Temple service and priestly support: the Jerusalem temple system that Paul alludes to was still functioning when he wrote (ca. 54-55 CE). Levites and priests received tithes and portions of sacrifices as explicit scriptural provision (Num 18:8-32; Deut 18:1-8). Josephus describes the priestly portions in detail (Antiquities 4.4.4).",
    "14": "The Lord's command about preacher support: Paul refers to the saying of Jesus preserved in Luke 10:7 (the laborer is worthy of his wages) and Matthew 10:10. This is among Paul's explicit references to Jesus tradition, treated as authoritative alongside scripture.",
    "15": "Paul's boast (kauchema) in free preaching: the concept of kauchema (boast, ground of boasting) in Greco-Roman culture was about the legitimate basis for claiming honor. Paul's unusual boast is not in accomplishments but in the act of giving up his rights — inverting the honor game.",
    "16": "Divine compulsion (anankē): the term carried weight in both Greek philosophy (necessity as cosmic force) and Jewish apocalyptic (divine decree). Paul uses it for the inescapable nature of his calling — he did not choose to be an apostle in the way a craftsman chooses a trade.",
    "17": "Stewardship (oikonomia): oikonomia was the management of a household estate, a major institution in Greek and Roman social life. The oikonomos (steward) was often a trusted slave who managed the master's affairs with full authority but no ownership. Paul frames his apostleship as exactly this — authority without ownership.",
    "18": "Working free of charge as the reward: Paul's paradox subverts the standard economic logic of wages. In a culture where artisans like Paul occupied a relatively low social status, his refusal to take fees from the community was both practically costly and socially puzzling.",
    "19": "Freedom through slavery — the Stoic paradox: Stoic philosophy, widely known in Corinth, held that the truly free person could not be enslaved even in chains, while the morally enslaved person remained a slave even if legally free. Paul inverts this by embracing voluntary slavery as the expression of true freedom.",
    "20": "Becoming as a Jew to win Jews: the flexibility Paul describes is consistent with his practice in Acts (circumcising Timothy in Acts 16:3; taking a Nazirite vow in Acts 18:18). Jewish identity markers (food laws, festival observance) were matters of cultural adaptation for Paul, not theological absolutes.",
    "21": "Those outside the law (anomos): Gentiles who had no Torah were anomos (without law) in Jewish categorization. Paul's ennomos Christou (within the law of Christ) introduces a new category: not Torah-observant, not lawless, but governed by Christ's own commandment.",
    "22": "The weak: the category of the weak (astheneis) in chapters 8-10 likely refers to Gentile converts who still felt the force of their former associations with idol worship. They were not weaker in faith but more susceptible to the pull of their pre-Christian religious world.",
    "23": "Becoming a co-participant (synkoinonos): the syg- compounds in Paul often signal the depth of communal participation he envisions. Synkoinonos is sharing-in-common rather than merely adjacent; Paul aims not just to serve the gospel but to be fully embedded in its community life.",
    "24": "The Isthmian Games: Corinth hosted the Isthmian Games every two years, second in prestige only to the Olympics. Corinthians were particularly familiar with competitive athletics — the stadium metaphor would have been vivid and immediate, not merely theoretical.",
    "25": "The perishable crown (stephanos): winners at the Isthmian Games received a pine or wild celery wreath (as opposed to the olive of Olympia). The Corinthians knew precisely how quickly such wreaths wilted. Paul's contrast with the imperishable crown (aphtharton) would have been pointed for those who had witnessed or competed in the games.",
    "26": "The agōn word-group: agōn (contest), agōnizomai (compete), was used for athletic and military contests alike. In Jewish literature (2 Macc 14:18; 4 Macc 6:10; 16:16), it became a metaphor for the struggle of the faithful under persecution. Paul inherits both the Greek athletic and the Jewish martyrological uses.",
    "27": "Hypōpiazō (beat under the eye, discipline the body): the boxing metaphor is precise — hypōpion was the area under the eye, the target of a well-landed punch. Paul's bodily self-discipline is not ascetic self-punishment but strategic preparation for the contest, like an athlete's training regimen.",
  },
  "10": {
    "1": "The wilderness generation as our fathers: Paul's inclusion of Gentile Corinthians in Israel's story is striking. By calling the Exodus generation our fathers, he adopts Gentile believers into the narrative of Israel — a move that reflects his understanding of the church as the eschatological Israel.",
    "2": "Baptism into Moses: the analogy is typological, not sacramental identity. The cloud (Exod 13:21; Num 14:14) and the sea (Exod 14:22) functioned as Israel's initiation into the Mosaic covenant — structurally parallel to the church's water baptism into Christ.",
    "3": "Spiritual food (broma pneumatikon): the manna of Exodus 16 is reread as pneumatikon — Spirit-bearing, having a deeper reality that points beyond itself. Paul applies a hermeneutic he learned from Jewish scripture interpretation (compare Wisdom of Solomon 16:20-21, which calls manna the food of angels).",
    "4": "The rock that followed: a rabbinic tradition (Tosefta Sukkah 3:11; Pseudo-Philo Biblical Antiquities 10:7) held that the water-bearing rock of Numbers 20 miraculously traveled with Israel through the wilderness. Paul adopts this tradition and identifies the rock as Christ — a pre-incarnate divine presence in Israel's story.",
    "5": "The majority perished: of the adult males who left Egypt in the Exodus, only Joshua and Caleb entered Canaan (Num 14:29-30). The word katastrephō (scatter, overthrow) echoes the LXX language of divine judgment on Israel's rebellions.",
    "6": "Typoi (patterns/types): the term is key to Paul's exegesis. In Hellenistic rhetorical culture, typos meant a pattern, impression, or mold. Paul applies it to the Exodus events as divinely designed prefigurations whose full meaning appears only in the church age.",
    "7": "The golden calf — Exodus 32:6: Paul cites the LXX exactly. The Israelite feast at Sinai combined eating, drinking, and pagan revelry (paizein, to play/sport, often with sexual connotation in LXX). The explicit parallel to Corinthian idol-feast participation is intentional.",
    "8": "The Baal Peor incident (Numbers 25): the 23,000 figure (vs. 24,000 in Num 25:9) may reflect a different counting tradition or a specific sub-event. The Phinehas story in Numbers 25 connects sexual immorality and idolatry explicitly — precisely the combination Paul is addressing in chapters 5-10.",
    "9": "Testing Christ in the wilderness: the serpent plague of Numbers 21:5-6 arose when Israel spoke against God and Moses. Paul's identification of the pre-incarnate Christ as the one being tested links his christology of Christ's wilderness presence (v.4) to the warning.",
    "10": "The Destroyer (olothreutēs): the term appears in Exodus 12:23 for the destroying angel of the Passover. Numbers 14:37 and 16:49 record plague-deaths connected to Israel's murmuring. The figure of the Destroyer appears also in Jewish apocalyptic (Jubilees 49:2; Wisdom 18:25).",
    "11": "The ends of the ages (ta telē tōn aiōnōn): Paul's eschatological self-location. Jewish apocalyptic divided history into ages (olam, aiōn); the messianic age was the telos (end-point and goal) of the earlier ages. Paul places the church at the hinge-point where the ages converge.",
    "12": "The danger of self-confidence: in Jewish wisdom tradition (Prov 16:18; Sir 32:21), overconfidence precedes the fall. The Corinthians who pride themselves on their gnōsis are exhibiting precisely the arrogance the wisdom tradition identifies as the condition for disaster.",
    "13": "Temptation common to humanity (anthropinos): Paul assures them that their testing is not superhuman — it belongs to the human condition. The phrase echoes philosophical discussions of human endurance (metriopatheia in Stoicism) and Jewish prayer for not being led into testing (cf. the Lord's Prayer).",
    "14": "Flee idolatry (pheugete eidōlolatrian): the verb pheugō (flee) appears in Jewish moral exhortation for sexual immorality (Gen 39:12; Joseph flees Potiphar's wife) and in NT ethical teaching (2 Tim 2:22). The urgency of flight rather than negotiation reflects the zero-tolerance stance of Jewish monotheism toward idol-worship.",
    "15": "Addressing them as sensible (phronimoi): the word phronimos (prudent, sensible, wise) was a term of honor in Greek culture — the phronimos was the person whose good judgment could be trusted. Paul uses the term with mild irony given the Corinthians' self-regard as the wise ones (sophoi) of chapter 1.",
    "16": "The cup of blessing — Passover context: the phrase potērion tēs eulogias (cup of blessing) is the Aramaic-Hebrew kos shel berakha, the third cup of the Passover Seder, blessed and shared after the main meal. Paul's Last Supper liturgy emerges from the Passover setting.",
    "17": "One bread, one body: in Hellenistic club-culture (thiasoi, collegia), sharing a common meal created social solidarity. Paul intensifies this: the shared loaf does not merely symbolize unity but constitutes the body. The bread is not a sign pointing elsewhere — it is the thing itself.",
    "18": "Israel according to the flesh: the phrase kata sarka (according to the flesh) distinguishes from Israel according to the Spirit (Rom 9:6-8). Paul draws on actual temple practice: Leviticus 7:14-18 shows that eating the peace offering created a bond with the altar and hence with Israel's God.",
    "19": "Idol as nothing: the standard Jewish polemic against idols is developed at length in Isaiah 44:9-20, Psalm 115:4-8, and Wisdom of Solomon 13-15. Paul stands in this tradition: the idol has no ontological reality as a divine being.",
    "20": "Demons behind the idols: Deuteronomy 32:17 (they sacrificed to demons, not to God) is the scriptural basis. Jubilees 22:17 and 1 Enoch 99:7 similarly identify idol-worship with demon-worship. Paul is not introducing a new idea but drawing on established Jewish demonology.",
    "21": "Two tables — the tablecloth of the Lord: the phrase trapeza kyriou (table of the Lord) appears in Malachi 1:7, 12 for the altar of the Jerusalem temple. Paul transfers it to the Eucharistic meal, creating an implicit argument: just as Jews cannot eat at the Lord's altar and at a foreign altar, so Christians cannot eat at the Lord's table and at a demon's table.",
    "22": "Provoking the Lord's jealousy: Deuteronomy 32:21 (the Song of Moses) — they provoked me with what is not God. The divine jealousy (qin'ah/zelos) is the response of the covenant God to Israel's idolatry throughout the Deuteronomistic history. Paul applies this covenant category to the church.",
    "23": "The Corinthian slogan (all things are permissible): this appears to be a phrase some Corinthians used, possibly derived from Pauline preaching about freedom from Torah-regulations. Paul quotes it back and qualifies it with the criteria of benefit (sympherei) and edification (oikodomei).",
    "24": "The neighbor-principle: Paul's ethical reorientation from individual rights to communal benefit echoes the love-commandment (Lev 19:18; Matt 22:39). The neighbor (plesion) in Jewish usage meant primarily the fellow member of the covenant community.",
    "25": "The macellum (meat market): the Corinthian agora had a macellum (meat market — confirmed by archaeological inscription from Corinth reading MACELLVM). Meat sold there could have come from temple sacrifice, from private slaughter, or from public festivals. Paul advises not to investigate provenance — buy and eat without scrupulous questioning.",
    "26": "Psalm 24:1 (the earth is the Lord's): the Psalm was used in Jewish table liturgy — the Talmud (b. Berakhot 35a) records that this verse was recited before eating as acknowledgment that all food belongs to God. Paul invokes the same liturgical tradition to ground his practical advice.",
    "27": "Dining with unbelievers: private dinner invitations were a major mechanism of social networking in Roman Corinth. To refuse all invitations from unbelievers would effectively withdraw from civic life. Paul's advice to attend and eat freely maintains the church's social engagement.",
    "28": "Hierothyton (pagan term for idol meat): the unbeliever uses the pagan term hierothyton (sacrificed to a sacred place) rather than Paul's polemical eidōlothyton (sacrificed to an idol). Paul switches to the pagan's own vocabulary, showing sensitivity to the social context of the dinner.",
    "29": "The conscience of the other: Paul's distinction between one's own conscience and the other's conscience draws on Stoic moral psychology, where syneidesis (conscience) was the internal faculty that judges one's own actions and renders verdicts. Paul makes it relational rather than merely individual.",
    "30": "Eating with thanksgiving (eucharistia): the practice of giving thanks before meals was standard in both Jewish (birkat ha-mazon, the blessing after meals) and early Christian communities. The Didache (9:1-3) preserves early eucharistic prayers that echo this thanksgiving tradition.",
    "31": "All to the glory of God: the comprehensive formula eis doxan theou (to the glory of God) appears in Jewish liturgical contexts (the Kaddish praises God's name) and in early Christian doxologies. Paul makes it the regulating principle for all conduct, including eating and drinking.",
    "32": "Three communities — Jews, Greeks, church: this tripartite division is characteristic of Paul's social world-view. The church is neither Jewish nor Greek but a new community created by the gospel — what he calls the new creation (2 Cor 5:17; Gal 6:15) and elsewhere the one new man (Eph 2:15).",
    "33": "Pleasing all people (areskein pasin): the goal of pleasing all people was a philosophical concept in Hellenistic ethics — the Stoics distinguished between proper and improper forms of people-pleasing. Paul's formulation avoids sycophancy by anchoring it in the salvation of the many rather than personal advancement.",
  },
  "11": {
    "1": "Imitation of Paul as imitation of Christ: the imitation theme (mimēsis) was central to ancient pedagogy. The disciple learned by observing and reproducing the master's behavior. In the Jewish tradition, disciples walked behind their rabbi to learn his gait, mannerisms, and practice as well as his teaching.",
    "2": "Oral traditions (paradoseis): before the NT documents were written and circulated, the communities relied on oral paradosis (tradition, handed-on teaching). Paul's reference to traditions he delivered to the Corinthians reflects the early church's sophisticated tradition-transmission network.",
    "3": "Head (kephalē) in Greco-Roman culture: in Greek physiology (Plato, Timaeus 44D; Aristotle, On the Parts of Animals 2.7), the head was the ruling part of the body and the seat of reason and authority. In LXX usage, kephalē often translates rosh (head of a tribe, head of an army — a positional/authority meaning).",
    "4": "Veiling in Roman religious practice: Roman men covered their heads (capite velato) during sacrifice and prayer — an act of pietas visible in countless Roman sculptures and reliefs. This Roman practice is likely what Paul is correcting: men bringing Roman civic-religious customs into Christian worship.",
    "5": "Women's head-coverings in the ancient Mediterranean: Greek, Roman, and Jewish women typically covered their heads in public settings. The unveiled woman risked being read as sexually available or as a slave (who had no honor to protect). Paul's instruction aligns with cross-cultural Mediterranean honor conventions while affirming women's participation in prayer and prophecy.",
    "6": "Shaved head as shame marker: in the ancient world, shaving a woman's head was a punishment for adultery (Num 5:18 may imply this) and a mark of mourning. Tacitus (Germania 19) describes Germanic tribes shaving adulterous women's heads. The shame of the shaved head illustrates why a bare head dishonors.",
    "7": "Image and glory (eikōn and doxa): eikōn comes from Genesis 1:26-27 (humans made in the image of God). The word doxa (glory) reflects the Hebrew kavod — the manifest weightiness of a person's honor and status. Paul's argument is that the different glory-relations between man and God vs. woman and man call for different practices.",
    "8": "Woman from man (Genesis 2): the creation sequence of Genesis 2:21-22 (woman formed from man's rib) is the scriptural basis. Paul is reading Genesis 2 as establishing the relational orientation of the first couple — not as establishing hierarchy of value but of derivation.",
    "9": "Made for man — Genesis 2:18: the Hebrew ezer (helper, partner) of Genesis 2:18 is not a diminutive term — it is used for God himself as Israel's helper (Ps 121:2). Paul's argument from creation purpose does not reduce woman to instrument but describes the original relational design.",
    "10": "Authority on her head because of the angels: the most debated phrase in the passage. Possible backgrounds: (1) Genesis 6:1-4 traditions about angels attracted by women's beauty; (2) Qumran texts (1QSa; 1QM) that excluded the physically impaired from holy assembly because of the angels present; (3) the idea that angels observe and report on worship (Ps 138:1 LXX). The exousia (authority) on her head is best read as the covering that grants her the authority to pray and prophesy.",
    "11": "In the Lord (en kyriō) — mutuality: Paul's qualifier introduces the eschatological community where the creation-order asymmetries are being transcended without being abolished. The phrase en kyriō is Paul's standard way of marking the sphere where the new creation's logic applies.",
    "12": "All things from God: the theological anchor that closes the creation-order argument. God is the source of both man and woman; the relational ordering serves the community without establishing permanent inferiority. This is consistent with Galatians 3:28 (neither male nor female in Christ Jesus).",
    "13": "Judgment from the community: Paul appeals to the Corinthians' own sense of propriety (to prepon — what is fitting/seemly). This was a key concept in Stoic and Aristotelian ethics: decorum was what fitted the nature and situation of the actor.",
    "14": "Nature (physis) as teacher: the appeal to physis (nature) was common in Stoic argumentation — nature itself teaches what is right. Paul's use here is more like convention or universal human practice than philosophical nature-reasoning; what nature teaches is what all cultures recognize as normal.",
    "15": "Long hair as natural covering: the peribolaion (covering, wrap) of a woman's long hair as her natural head-covering makes a physiological argument: women's hair naturally grows longer, suggesting a natural provision for modesty. The argument was accessible without recourse to theology.",
    "16": "Universal church practice as the settling criterion: Paul closes the head-covering discussion not with a theological ruling but a sociological one. The churches of God everywhere follow this practice — the Corinthians are deviant, not exemplary. The appeal to universal custom (not just his own opinion) is a rhetorical move appropriate to a community that prized their distinctiveness.",
    "18": "Divisions (schismata) in the assembly: the word schisma (from schizō, to split) — same root as the English schism — appeared in 1:10 for the party-factions around apostolic names. Now it reappears in 11:18 for the social divisions that have infected the common meal. The word migrates from theological to social context.",
    "19": "Haireseis (factions/heresies): hairesis originally meant a choice or a school of thought (Josephus uses it for the Pharisees, Sadducees, and Essenes as three haireseis of Judaism — Antiquities 13.5.9). Paul uses it for the factions that reveal who is genuinely approved (dokimoi) — a testing-sieve function.",
    "20": "The Lord's Supper (kyriakon deipnon): the adjective kyriakos (belonging to the Lord) appears only here and in Revelation 1:10 (the Lord's Day, kyriakē hēmera) in the NT. It became the technical name for the Christian communal meal and eventually for the Eucharist (kyriakē in later Greek, dominica in Latin).",
    "21": "Social stratification at the meal: Roman dinner conventions divided guests by social rank. The triclinium (formal dining room) accommodated the host's inner circle with fine food and wine while lower-status guests received lesser portions in the atrium. The Corinthian Lord's Supper apparently reproduced this Roman social hierarchy within the congregation.",
    "22": "Shaming those who have nothing: the Greek phrase tous mē echontas (those who have nothing/nothing to bring) indicates poor members who came to the communal meal without provisions. In a patronage economy, bringing nothing marked one as a dependent; the host's early eating humiliated them in front of the whole assembly.",
    "23": "The tradition Paul received (paralambanō): Paul claims to have received the Supper tradition from the Lord himself (apo tou kyriou). This does not necessarily mean direct revelation; it may mean that the tradition ultimately derives from Jesus — received through the apostolic chain from its Lord-given origin.",
    "24": "In remembrance (eis tēn emēn anamnēsin): anamnēsis in Greek has a richer meaning than mere cognitive recall. In LXX cultic contexts (Num 10:10; Lev 24:7), the memorial was an action that re-presented the saving event before God, not merely brought it to mind. The Passover Haggadah's instruction (Mishnah Pesahim 10:5) that each generation must see itself as having come out of Egypt reflects the same participatory remembrance.",
    "25": "New covenant (kainē diathēkē): the phrase comes from Jeremiah 31:31-34, the promise of a new covenant written on hearts rather than stone. No other Jewish text before Paul explicitly calls the cup the new covenant in blood — this is a distinctively Christian theological formulation of the Last Supper tradition.",
    "26": "Until he comes (achri hou elthē): the eschatological orientation of the Supper — it is a meal between the first and second comings, combining memorial of the past with anticipation of the future. The verb katangellete (you proclaim) makes the meal itself an act of proclamation, not merely a private ritual.",
    "27": "Eating and drinking in an unworthy manner (anaxiōs): the manner Paul condemns is specified in the context: going ahead without waiting for others, eating too much while the poor go hungry, treating it as a private meal rather than a communal rite. The guilt of the body and blood is the gravity of treating the Lord's death carelessly.",
    "28": "Self-examination (dokimazō): the verb dokimazō (test, approve after testing) was used for assaying metal and examining candidates for public office. Applied to Lord's Supper preparation, it called for communal and relational self-scrutiny — am I treating my fellow believers as members of Christ's body?",
    "29": "Discerning the body (diakrinōn to sōma): the failure Paul identifies is not abstract theological misunderstanding but the concrete failure to see the poor members as part of Christ's body. The word sōma here most likely refers to the community body (as in 12:12-27) rather than primarily the eucharistic elements, though both meanings may be in play.",
    "30": "Weakness, illness, and death in the congregation: Paul attributes some physical suffering and death among the Corinthians to divine discipline connected to eucharistic abuse. This is not a general theological claim about illness but a specific pastoral diagnosis of a particular community. The category of divine discipline (paideia) for God's children is common in Jewish wisdom (Prov 3:11-12; Heb 12:6).",
    "31": "If we judged ourselves (diekrinomen): the conditional implies that self-examination before the Supper forestalls divine judgment. The judicial language (krisis, krina, diakrinō) dominates vv. 28-32, framing the Lord's Supper as the setting for a preliminary verdict that shapes one's standing before the final judgment.",
    "32": "Discipline (paideia) vs. condemnation (katakrithōmen): the distinction between the Lord's corrective discipline of believers and condemnation with the world is a key pastoral category. Paideia (discipline, training) was the term for the formation of character through education and correction — the Father's loving investment in children's growth.",
    "33": "Wait for one another (ekdechesthe): the word ekdechomai (to wait for, receive, welcome) appears in Hebrews 10:13 and 11:10 for patient waiting for God's promises. Applied to the Lord's Supper, it calls for the kind of patient mutual attention that the Roman dinner-stratification had eroded.",
    "34": "The rest Paul will arrange in person: the phrase ta de loipa hōs an elthō diataxomai (the rest I will arrange when I come) implies that 11:2-34 does not exhaust the practical issues; Paul intends to handle additional matters face-to-face. This closing gesture maintains his apostolic authority over the community's worship practices.",
  }
}

if __name__ == '__main__':
    existing = load_comm('mkt-context', '1corinthians')
    merge_comm(existing, NEW)
    save_comm('mkt-context', '1corinthians', existing)
    for ch in ['9', '10', '11']:
        print(f'  ch {ch}: {len(existing.get(ch, {}))} verses')
